import uCharts from '@/components/u-charts/u-charts.js';
import wPicker from '@/components/w-picker/w-picker.vue';
import liChoose from '@/components/li-choose/li-choose.vue';
import { isJSON } from '@/common/checker.js';
var _self;
var canvaPie = null;
export default {
	components: {
		wPicker,
		liChoose
	},
	data() {
		return {
			scrollLeft: 0,
			mode: false,

			items: [],
			TabCur: 0,
			mask: false,
			mask1: false,
			pixelRatio: 1,
			textarea: '',
			typeText: '待完善',
			sourceText: '人脸识别',
			comeTimeText: '到访日期',
			timeText: '时间正序',
			requestData: {
				source: 1, //来源类型(1-人脸识别，2-微信客户，3-小程序扫码)
				over_type: '', //按客户房号、名称和电话关键字进行查询
				type: 3, //按客户归属查询（1我负责的，2共享给我的，3全部客户，4客户共池）
				keyword: '', //搜索
				sort: 1, //进行排序（1：按创建时间正叙，2：按创建时间倒叙）
				pid: '', //	按项目进行查询
				page: 1,
				status:0,//是否完善过（0-未完善，1-已完善）
				date:''
			},
			per_page: 0,
			customerList: [],
			total: 0,
			current_page: 0,
			last_page: 0,
			tmp_id: '',
			checkbox: [
				{
					value: 'A',
					checked: true
				},
				{
					value: 'B',
					checked: true
				},
				{
					value: 'C',
					checked: false
				}
			]
		};
	},
	onShow() {
		_self = this;
		this.getUntreatedCustomer();
	},
	onReachBottom() {
		console.log(111);
	},
	methods: {
		ChangeChecked(item) {
			if (item.checked == true) {
				item.checked = false;
			}
			if (item.checked == false) {
				item.checked = true;
			}
			this.$forceUpdate();
		},
		RadioChange(e) {
			this.tmp_id = e.detail.value;
		},
		clickType() {
			let _this = this;
			let items = ['待完善', '已完善'];
			uni.showActionSheet({
				itemList: items,
				success: function(res) {
					_this.typeText = items[res.tapIndex];
					_this.requestData.status = res.tapIndex;
					_this.requestData.page = 1;
					_this.customerList = [];
					_this.getUntreatedCustomer();
				}
			});
		},
		clickSource() {
			let _this = this;
			let items = ['人脸识别'];
			uni.showActionSheet({
				itemList: items,
				success: function(res) {
					_this.sourceText = items[res.tapIndex];
					_this.requestData.source = res.tapIndex + 1;
					_this.requestData.page = 1;
					_this.customerList = [];
					_this.getUntreatedCustomer();
				}
			});
		},
		clickComeTime() {
			this.$refs.yearMonth.show();
		},
		clickTime() {
			let _this = this;
			let items = ['时间正序', '时间倒序'];
			uni.showActionSheet({
				itemList: items,
				success: function(res) {
					_this.timeText = items[res.tapIndex];
					_this.requestData.sort = res.tapIndex + 1;
					_this.requestData.page = 1;
					_this.customerList = [];
					_this.getUntreatedCustomer();
				}
			});
		},
		getUntreatedCustomer() {
			this.$api.customUntreatedcustomlistcustomapi(this.requestData, res => {
				res.data.data.forEach(resp => {
					resp.checked = false;
					this.customerList.push(resp);
				});
				this.per_page = res.data.per_page; //一页多少条数据；
				this.current_page = res.data.current_page; //当前页数；
				this.last_page = res.data.last_page; //一共多少页；
				this.total = res.data.total; //总条数
			});
		},
		perfectData() {
			let tmp_ids = [];
			this.customerList.forEach(res => {
				if (res.checked == true) {
					tmp_ids.push(res.tmp_id);
				}
			});
			if (tmp_ids.length != 0) {
				let tmp_id = this.$tools.toStrings(tmp_ids);
				uni.navigateTo({
					url: '/pages/customer/customer_add?tmp_id=' + tmp_id
				});
			}
		},
		detail(items) {
			uni.navigateTo({
				url: '/pages/customer/overdue_customer_detail?id=' + items
			});
		},
		InputFocus() {},
		InputBlur() {},
		confirms(data) {
		},
		toggleTab(str) {
			this.$refs[str].show();
		},
		onConfirm(val) {
			let resultInfo = { ...val };
			this.requestData.date = resultInfo.result;
			this.comeTimeText =  resultInfo.result;
			this.customerList = [];
			this.requestData.page = 1;
			this.getUntreatedCustomer();
		},
		chooseProject() {
			this.$refs.lichoose.show();
		},
		checkboxChange(e) {
			var items = this.customerList;
			let values = e.detail.value;
			for (var i = 0, lenI = this.customerList.length; i < lenI; ++i) {
				this.customerList[i].checked = false;
				for (var j = 0, lenJ = values.length; j < lenJ; ++j) {
					if (i + '1' == values[j]) {
						this.customerList[i].checked = true;
						break;
					}
				}
			}
		},
		tabSelect(e) {
			this.TabCur = e.currentTarget.dataset.id;
			this.scrollLeft = (e.currentTarget.dataset.id - 1) * 60;
		}
	}
};
